array_filter(
					$this->tracked_events,
					function ( $event ) {
						if ( ! $event instanceof Event ) {
							return false;
						}

						$event_name = $event->get_name();
						if ( 'Lead' !== $event_name ) {
							return false;
						}

						$custom_data = $event->get_custom_data();
						return is_array( $custom_data )
							&& isset( $custom_data['fb_integration_tracking'] )
							&& 'wpforms-lite' === $custom_data['fb_integration_tracking'];
					}
				)

